import anthropic

client = anthropic.Anthropic()

SYSTEM = """
You are a code-review agent. Before each action, reason out loud:
  Observation: <what you just learned from the last tool result>
  Plan: <what you intend to do next and why>
  Action: <the tool you will call, or 'done' if you have the answer>

This format must appear before every tool call and before your final answer.
"""

TOOLS = [
    {
        "name": "read_file",
        "description": "Read the full content of a source file.",
        "input_schema": {
            "type": "object",
            "properties": {"path": {"type": "string"}},
            "required": ["path"],
        },
    },
    {
        "name": "search_code",
        "description": "Search for files or symbols by pattern.",
        "input_schema": {
            "type": "object",
            "properties": {"query": {"type": "string"}},
            "required": ["query"],
        },
    },
]

def run_cot_agent(task: str, handlers: dict, max_turns: int = 10) -> str:
    messages = [{"role": "user", "content": task}]

    for _ in range(max_turns):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=2048,
            system=SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            for block in reversed(response.content):
                if block.type == "text":
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type != "tool_use":
                continue
            fn = handlers.get(block.name)
            result = fn(**block.input) if fn else f"Unknown tool: {block.name}"
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": block.id,
                "content": str(result),
            })
        messages.append({"role": "user", "content": tool_results})

    raise RuntimeError("Agent did not terminate within max_turns")

import anthropic

client = anthropic.Anthropic()

def decompose_and_solve(complex_question: str) -> str:
    """
    Phase 1: decompose the question into independent sub-problems.
    Phase 2: solve each sub-problem independently (CoT per sub-problem).
    Phase 3: synthesize sub-answers into a final answer.
    """

    # Phase 1: decompose
    decompose_resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{
            "role": "user",
            "content": (
                f"Break the following question into independent sub-problems, "
                f"one per line, numbered. Do not answer them yet.\n\n{complex_question}"
            ),
        }],
    )
    subproblems_text = decompose_resp.content[0].text
    subproblems = [
        line.lstrip("0123456789.) ").strip()
        for line in subproblems_text.strip().splitlines()
        if line.strip()
    ]

    # Phase 2: solve each sub-problem with CoT
    sub_answers = []
    for sub in subproblems:
        resp = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=512,
            messages=[{
                "role": "user",
                "content": f"{sub}\n\nThink step by step.",
            }],
        )
        sub_answers.append(f"Q: {sub}\nA: {resp.content[0].text}")

    # Phase 3: synthesize
    synthesis_input = "\n\n".join(sub_answers)
    synthesis_resp = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        messages=[{
            "role": "user",
            "content": (
                f"Using the following solved sub-problems, answer the original question:\n\n"
                f"Original question: {complex_question}\n\n"
                f"Sub-problem answers:\n{synthesis_input}"
            ),
        }],
    )
    return synthesis_resp.content[0].text
